// mockSilenceManager is a test implementation of SilenceManager.
type mockSilenceManager struct {
	silences []*Silence
	err      error
	idPrefix string
}

func (m *mockSilenceManager) CreateSilence(s *Silence) (string, error) {
	if m.err != nil {
		return "", m.err
	}
	id := fmt.Sprintf("%s-%d", m.idPrefix, len(m.silences))
	m.silences = append(m.silences, s)
	return id, nil
}

// validSilence returns a well-formed Silence for use in tests.
func validSilence(name, value string) Silence {
	now := time.Now()
	return Silence{
		Matchers: []SilenceMatcher{
