   103		// Validate all silences before creating any (atomic semantics).
   104		for i := range silences {
   105			if err := validateSilence(&silences[i]); err != nil {
   106				bulkErr := &bulkSilenceError{Index: i, Message: err.Error()}
   107				return apiFuncResult{nil, &apiError{errorBadData, bulkErr}, nil, nil}
   108			}
   109		}
   110	
   111		// All silences are valid; create them.
   112		ids := make([]string, 0, len(silences))
   113		for i := range silences {
   114			id, err := api.silenceManager.CreateSilence(&silences[i])
   115			if err != nil {
   116				return apiFuncResult{nil, &apiError{errorInternal, fmt.Errorf("creating silence at index %d: %w", i, err)}, nil, nil}
   117			}
   118			ids = append(ids, id)
   119		}
   120	
   121		return apiFuncResult{ids, nil, nil, nil}
   122	}
